+/*
+ * Copyright (c) Facebook, Inc. and its affiliates.
+ * All rights reserved.
+ *
+ * This source code is licensed under the BSD-style license found in the
+ * LICENSE file in the root directory of this source tree.
+ */
+
+#include <algorithm>
+#include <cmath>
+#include <functional>
+#include <random>
+#include <vector>
+
+#include <qnnpack.h>
+
+#include <benchmark/benchmark.h>
+
+
+static void sigmoid_q8(benchmark::State& state) {
+  const size_t batchSize = static_cast<size_t>(state.range(0));
+  const size_t channels = static_cast<size_t>(state.range(1));
+
+  std::random_device randomDevice;
+  auto rng = std::mt19937(randomDevice());
+  auto u8rng = std::bind(std::uniform_int_distribution<uint8_t>(), rng);
+
+  std::vector<uint8_t> input(batchSize * channels);
+  std::vector<uint8_t> output(batchSize * channels);
+  std::generate(input.begin(), input.end(), std::ref(u8rng));
+  std::fill(output.begin(), output.end(), 0xA5);
+
+  qnnp_status status = qnnp_initialize();
+  if (status != qnnp_status_success) {
+    state.SkipWithError("failed to initialize QNNPACK");
+  }
+
+  qnnp_operator_t sigmoidOperator = nullptr;
+  status = qnnp_create_sigmoid_nc_q8(
+    channels,
+    127 /* input zero point */, 1.0f /* input scale */,
+    0 /* output zero point */, 1.0f / 256.0f /* output scale */,
+    0 /* output min */, 255 /* output max */,
+    &sigmoidOperator);
+  if (status != qnnp_status_success || sigmoidOperator == nullptr) {
+    state.SkipWithError("failed to create Sigmoid operator");
+  }
+
+  status = qnnp_setup_sigmoid_nc_q8(
+    sigmoidOperator,
+    batchSize,
+    input.data(), channels /* input:stride */,
+    output.data(), channels /* output:stride */);
+  if (status != qnnp_status_success) {
+    state.SkipWithError("failed to setup Sigmoid operator");
+  }
+
+  for (auto _ : state) {
+    status = qnnp_run_operator(sigmoidOperator, nullptr /* thread pool */);
+    if (status != qnnp_status_success) {
+      state.SkipWithError("failed to run Sigmoid operator");
+    }
+  }
+
+  const size_t itemsPerIteration = batchSize * channels;
+  state.SetItemsProcessed(int64_t(state.iterations()) * int64_t(itemsPerIteration));
+
+  const size_t bytesPerIteration = 2 * itemsPerIteration * sizeof(uint8_t);
+  state.SetBytesProcessed(int64_t(state.iterations()) * int64_t(bytesPerIteration));
+
+  status = qnnp_delete_operator(sigmoidOperator);
+  if (status != qnnp_status_success) {
+    state.SkipWithError("failed to delete Sigmoid operator");
+  }
+}
+
+static void CharacteristicArguments(benchmark::internal::Benchmark* b)
+{
+  b->ArgNames({"N", "C"});
+
+  int32_t c = 16;
+  for (int32_t n = 224; n >= 7; n /= 2) {
+    b->Args({n * n, c});
+    c *= 2;
+  }
+}
+
+BENCHMARK(sigmoid_q8)->Apply(CharacteristicArguments);
+
+#ifndef QNNPACK_BENCHMARK_NO_MAIN
+BENCHMARK_MAIN();
+#endif
