+TEST(LEAKY_RELU_OP, unit_batch_with_qmin) {
+  for (size_t channels = 1; channels < 100; channels += 15) {
+    LeakyReLUOperatorTester()
+      .batchSize(1)
+      .channels(channels)
+      .qmin(128)
+      .iterations(3)
+      .testQ8();
+  }
+}
+
+TEST(LEAKY_RELU_OP, unit_batch_with_qmax) {
+  for (size_t channels = 1; channels < 100; channels += 15) {
+    LeakyReLUOperatorTester()
+      .batchSize(1)
+      .channels(channels)
+      .qmax(128)
+      .iterations(3)
+      .testQ8();
+  }
+}
+
+TEST(LEAKY_RELU_OP, unit_batch_with_negative_slope) {
+  for (size_t channels = 1; channels < 100; channels += 15) {
+    for (float negativeSlope = 1.0e-4f; negativeSlope < 1.0f; negativeSlope *= 3.14159265f) {
+      LeakyReLUOperatorTester()
+        .batchSize(1)
+        .channels(channels)
+        .negativeSlope(negativeSlope)
+        .iterations(1)
+        .testQ8();
+    }
+  }
+}
+
+TEST(LEAKY_RELU_OP, unit_batch_with_input_scale) {
+  for (size_t channels = 1; channels < 100; channels += 15) {
+    for (float inputScale = 1.0e-2f; inputScale < 1.0e+2f; inputScale *= 3.14159265f) {
+      LeakyReLUOperatorTester()
+        .batchSize(1)
+        .channels(channels)
+        .inputScale(inputScale)
+        .iterations(1)
