+class MaxPoolingOperatorTester {
+ public:
+  inline MaxPoolingOperatorTester& padding(uint32_t padding) {
+    this->paddingTop_ = padding;
+    this->paddingRight_ = padding;
+    this->paddingBottom_ = padding;
+    this->paddingLeft_ = padding;
