+
+void u8maxpool_ukernel_16x9p8q__neon(
+    size_t n,
+    size_t ks,
+    size_t kc,
+    const uint8_t** input,
+    uint8_t* output,
+    size_t input_increment,
+    size_t output_increment,
+    const union qnnp_maxpool_quantization_params quantization_params[restrict static 1])
+{
+  assert(n != 0);
+  assert(ks != 0);
+  assert(kc != 0);
+  assert(kc < 16);
+
+  const uint8x16_t voutput_max = vld1q_dup_u8(&quantization_params->neon.output_max);
+  const uint8x16_t voutput_min = vld1q_dup_u8(&quantization_params->neon.output_min);
+  do {
+    uint8_t* o = output;
+    {
+      const uint8_t* i0 = *input++;
+      const uint8_t* i1 = *input++;
+      const uint8_t* i2 = *input++;
+      const uint8_t* i3 = *input++;
+      const uint8_t* i4 = *input++;
+      const uint8_t* i5 = *input++;
+      const uint8_t* i6 = *input++;
+      const uint8_t* i7 = *input++;
+      const uint8_t* i8 = *input++;
+      if (ks < 2) {
+        i1 = i0;
+      }
+      if (ks <= 2) {
+        i2 = i0;
+      }
+      if (ks < 4) {
+        i3 = i0;
+      }
+      if (ks <= 4) {
+        i4 = i0;
