new file mode 100644
index 0000000..8295c54
--- /dev/null
+++ b/src/u8maxpool/sub16-sse2.c
@@ -0,0 +1,85 @@
+/*
+ * Copyright (c) Facebook, Inc. and its affiliates.
+ * All rights reserved.
+ *
+ * This source code is licensed under the BSD-style license found in the
+ * LICENSE file in the root directory of this source tree.
+ */
+
+#include <assert.h>
+
+#include <emmintrin.h>
+
+#include <qnnpack/u8maxpool.h>
+
+
+void u8maxpool_ukernel_sub16__sse2(
+    size_t n,
+    size_t ks,
+    size_t kc,
+    const uint8_t** input,
+    uint8_t* output,
+    size_t input_increment,
+    size_t output_increment,
+    const union qnnp_maxpool_quantization_params quantization_params[restrict static 1])
+{
+  assert(n != 0);
+  assert(ks != 0);
+  assert(kc != 0);
+  assert(kc < 16);
+
+  const __m128i voutput_max = _mm_load_si128((const __m128i*) quantization_params->sse2.output_max);
+  const __m128i voutput_min = _mm_load_si128((const __m128i*) quantization_params->sse2.output_min);
+
+  do {
+    __m128i vmax = _mm_setzero_si128();
+
+    size_t m = ks;
+    do {
+      const uint8_t* i = *input++;
+      i += kc;
+      __m128i vi = vmax;
+      if (kc & 1) {
+        i -= 1;
+        vi = _mm_cvtsi32_si128(*i);
+      }
+      if (kc & 2) {
+        vi = _mm_slli_epi32(vi, 16);
+        i -= 2;
+        vi = _mm_insert_epi16(vi, *((const uint16_t*) i), 0);
+      }
+      if (kc & 4) {
+        i -= 4;
+        vi = _mm_unpacklo_epi32(_mm_cvtsi32_si128((int) *((const uint32_t*) i)), vi);
+      }
+      if (kc & 8) {
+        i -= 8;
+        vi = _mm_unpacklo_epi64(_mm_loadl_epi64((const __m128i*) i), vi);
+      }
+      vmax = _mm_max_epu8(vmax, vi);
+    } while (--m != 0);
+    input = (const uint8_t**) ((uintptr_t) input + input_increment);
+    __m128i vout = _mm_max_epu8(_mm_min_epu8(vmax, voutput_max), voutput_min);
+
+    if (kc & 8) {
+      _mm_storel_epi64((__m128i*) output, vout);
+      output += 8;
+      vout = _mm_unpackhi_epi64(vout, vout);
+    }
+    if (kc & 4) {
+      *((uint32_t*) output) = (uint32_t) _mm_cvtsi128_si32(vout);
+      output += 4;
+      vout = _mm_srli_epi64(vout, 32);
+    }
+    if (kc & 2) {
+      *((uint16_t*) output) = (uint16_t) _mm_extract_epi16(vout, 0);
+      output += 2;
+      vout = _mm_srli_epi32(vout, 16);
+    }
+    if (kc & 1) {
+      *((uint8_t*) output) = (uint8_t) _mm_cvtsi128_si32(vout);
+      output += 1;
+    }
+    output = (uint8_t*) ((uintptr_t) output + output_increment);
+  } while (--n != 0);
+}
diff --git a/test/maxpool-microkernel-tester.h b/test/maxpool-microkernel-tester.h
new file mode 100644
index 0000000..7d9efef
--- /dev/null
+++ b/test/maxpool-microkernel-tester.h
@@ -0,0 +1,251 @@
+/*
+ * Copyright (c) Facebook, Inc. and its affiliates.
+ * All rights reserved.
+ *
+ * This source code is licensed under the BSD-style license found in the
+ * LICENSE file in the root directory of this source tree.
+ */
+
+#pragma once
+
+#include <cstddef>
+#include <cstdlib>
+#include <algorithm>
+#include <cmath>
+#include <functional>
+#include <random>
+#include <vector>
+
+#include <qnnpack.h>
+#include <qnnpack/params.h>
+#include <qnnpack/requantization.h>
+
+
+class MaxPoolMicrokernelTester {
+ public:
+  inline MaxPoolMicrokernelTester& n(size_t n) {
+    assert(n != 0);
+    this->n_ = n;
+    return *this;
+  }
+
+  inline size_t n() const {
+    return this->n_;
+  }
+
+  inline MaxPoolMicrokernelTester& s(size_t s) {
+    assert(s != 0);
+    this->s_ = s;
+    return *this;
+  }
+
+  inline size_t s() const {
+    return this->s_;
+  }
+
+  inline MaxPoolMicrokernelTester& kh(size_t kh) {
+    assert(kh != 0);
+    this->kh_ = kh;
+    return *this;
+  }
+
+  inline size_t kh() const {
+    return this->kh_;
+  }
+
+  inline MaxPoolMicrokernelTester& kw(size_t kw) {
+    assert(kw != 0);
+    this->kw_ = kw;
+    return *this;
+  }
+
+  inline size_t kw() const {
+    return this->kw_;
+  }
+
+  inline size_t ks() const {
+    return kh() * kw();
+  }
+
+  inline size_t packedKs() const {
+    if (kc() < kr()) {
+      return ks();
+    } else if (ks() <= mr()) {
+      return mr();
+    } else {
+      return (ks() - mr()) % qr() == 0 ? ks() : ((ks() - mr()) / qr() + 1) * qr() + mr();
+    }
+  }
+
+  inline MaxPoolMicrokernelTester& mr(size_t mr) {
+    assert(mr != 0);
+    this->mr_ = mr;
+    return *this;
+  }
+
+  inline size_t mr() const {
+    return this->mr_;
+  }
+
+  inline MaxPoolMicrokernelTester& qr(size_t qr) {
+    assert(qr != 0);
+    this->qr_ = qr;
+    return *this;
+  }
+
+  inline size_t qr() const {
+    return this->qr_;
+  }
+
+  inline MaxPoolMicrokernelTester& kc(size_t kc) {
+    assert(kc != 0);
+    this->kc_ = kc;
+    return *this;
+  }
+
+  inline size_t kc() const {
+    return this->kc_;
+  }
+
+  inline MaxPoolMicrokernelTester& kr(size_t kr) {
+    assert(kr != 0);
+    this->kr_ = kr;
+    return *this;
+  }
+
+  inline size_t kr() const {
+    return this->kr_;
+  }
+
+  inline size_t packedN() const {
+    return kc() % kr() == 0 ? kc() : (kc() / kr() + 1) * kr();
+  }
+
+  inline MaxPoolMicrokernelTester& xStride(size_t xStride) {
+    assert(xStride != 0);
+    this->xStride_ = xStride;
+    return *this;
+  }
+
+  inline size_t xStride() const {
+    if (this->xStride_ == 0) {
+      return kc();
+    } else {
+      assert(this->xStride_ >= kc());
+      return this->xStride_;
+    }
+  }
+
+  inline MaxPoolMicrokernelTester& yStride(size_t yStride) {
+    assert(yStride != 0);
+    this->yStride_ = yStride;
+    return *this;
+  }
+
+  inline size_t yStride() const {
+    if (this->yStride_ == 0) {
+      return kc();
+    } else {
+      assert(this->yStride_ >= kc());
+      return this->yStride_;
+    }
+  }
+
+  inline MaxPoolMicrokernelTester& qmin(uint8_t qmin) {
+    this->qmin_ = qmin;
+    return *this;
+  }
+
+  inline uint8_t qmin() const {
+    return this->qmin_;
+  }
+
+  inline MaxPoolMicrokernelTester& qmax(uint8_t qmax) {
+    this->qmax_ = qmax;
+    return *this;
+  }
+
+  inline uint8_t qmax() const {
+    return this->qmax_;
+  }
+
+  inline MaxPoolMicrokernelTester& iterations(size_t iterations) {
+    this->iterations_ = iterations;
+    return *this;
+  }
+
+  inline size_t iterations() const {
+    return this->iterations_;
+  }
+
+  void test(u8maxpool_ukernel_function u8maxpool) const {
+    std::random_device randomDevice;
+    auto rng = std::mt19937(randomDevice());
+    auto u8rng = std::bind(std::uniform_int_distribution<uint8_t>(), rng);
+
+    std::vector<const uint8_t*> indirectX(packedKs() + (n() * s() - 1) * kh());
+    std::vector<uint8_t> x((indirectX.size() - 1) * xStride() + kc());
+
+    std::vector<uint8_t> zero(kc());
+    std::vector<uint8_t> y((n() - 1) * yStride() + kc());
+    std::vector<uint8_t> yRef(n() * kc());
+    for (size_t iteration = 0; iteration < iterations(); iteration++) {
+      std::generate(x.begin(), x.end(), std::ref(u8rng));
+      std::fill(y.begin(), y.end(), 0xA5);
+
+      for (size_t i = 0; i < indirectX.size(); i++) {
+        indirectX[i] = x.data() + i * xStride();
+      }
+      std::shuffle(indirectX.begin(), indirectX.end(), rng);
+
+      /* Prepare quantization parameters */
+      const union qnnp_maxpool_quantization_params quantizationParams =
+        qnnp_compute_maxpool_quantization_params(qmin(), qmax());
+
+      /* Compute reference results */
+      for (size_t i = 0; i < n(); i++) {
+        for (size_t k = 0; k < kc(); k++) {
+          uint8_t maxValue = 0;
+          for (size_t j = 0; j < ks(); j++) {
+            maxValue = std::max(maxValue,
+              indirectX[i * s() * kh() + j][k]);
+          }
+          maxValue = std::min(maxValue, qmax());
+          maxValue = std::max(maxValue, qmin());
+          yRef[i * kc() + k] = maxValue;
+        }
+      }
+
+      /* Call optimized micro-kernel */
+      u8maxpool(n(), ks(), kc(),
+        indirectX.data(), y.data(),
+        (kh() * s() - packedKs()) * sizeof(void*),
+        (yStride() - kc()) * sizeof(uint8_t),
+        &quantizationParams);
+
+      /* Verify results */
+      for (size_t i = 0; i < n(); i++) {
+        for (size_t k = 0; k < kc(); k++) {
+          ASSERT_EQ(uint32_t(yRef[i * kc() + k]), uint32_t(y[i * yStride() + k]))
+            << "at pixel " << i << ", channel " << k << ", n = " << n()
+            << ", ks = " << kh() << "x" << kw() << " (" << ks() << "), kc = " << kc();
+        }
+      }
+    }
+  }
+
+ private:
+  size_t n_{1};
+  size_t s_{1};
+  size_t kh_{1};
+  size_t kw_{1};
+  size_t mr_{1};
+  size_t qr_{1};
+  size_t kc_{1};
+  size_t kr_{1};
+  size_t xStride_{0};
+  size_t yStride_{0};
+  uint8_t qmin_{0};
+  uint8_t qmax_{255};
+  size_t iterations_{15};
+};
