+#include <arm_neon.h>
+
+#include <qnnpack/x8zip.h>
+
+
+void qnnp_x8zip_x3__neon(
+	size_t n,
+	const void* input,
+	void* output)
+{
+	const uint8_t* x = input;
+	const uint8_t* y = x + n;
+	const uint8_t* z = y + n;
+	uint8_t* o = output;
+
+	if (n >= 8) {
+		do {
+			uint8x8x3_t vxyz;
+			vxyz.val[0] = vld1_u8(x); x += 8;
+			vxyz.val[1] = vld1_u8(y); y += 8;
+			vxyz.val[2] = vld1_u8(z); z += 8;
+			vst3_u8(o, vxyz); o += 24;
+			n -= 8;
+		} while (n >= 8);
+		if (n != 0) {
+			const size_t address_increment = n - 8;
+			uint8x8x3_t vxyz;
+			vxyz.val[0] = vld1_u8(x + address_increment);
+			vxyz.val[1] = vld1_u8(y + address_increment);
+			vxyz.val[2] = vld1_u8(z + address_increment);
+			vst3_u8((uint8_t*) ((uintptr_t) o + address_increment * 3), vxyz);
+		}
+	} else {
+		do {
+			const uint8_t vx = *x++;
+			const uint8_t vy = *y++;
+			const uint8_t vz = *z++;
+			o[0] = vx;
+			o[1] = vy;
+			o[2] = vz;
+			o += 3;
+		} while (--n != 0);
+	}
+}
