+
+					vst1_lane_u32(__builtin_assume_aligned(output, 1), vxyzw1, 0);
+					output = (void*) ((uintptr_t) output + m);
+
+					vst1_lane_u32(__builtin_assume_aligned(output, 1), vxyzw1, 1);
+					output = (void*) ((uintptr_t) output + m);
