+void qnnp_x8zip_xm__sse2(
+	size_t n,
+	size_t m,
+	const void* input,
+	void* output)
+{
+	const uint8_t* w = input;
+	const size_t input_increment = n * 3;
+	const size_t output_increment = 4 - m * n;
