+				output = (void*) ((uintptr_t) output + m);
+
+				*((uint32_t*) output) = _mm_cvtsi128_si32(vxyzw3);
+				output = (void*) ((uintptr_t) output + m);
+				vxyzw3 = _mm_shufflelo_epi16(vxyzw3, _MM_SHUFFLE(3, 2, 3, 2));
