+					output = (void*) ((uintptr_t) output + m);
+					vxyzw0 = vxyzw1;
+				}
+
+				if (k & 2) {
+					*((uint32_t*) output) = _mm_cvtsi128_si32(vxyzw0);
+					output = (void*) ((uintptr_t) output + m);
+					vxyzw0 = _mm_shufflelo_epi16(vxyzw0, _MM_SHUFFLE(3, 2, 3, 2));
