+static inline void pack_q8dw_w_dilation(
+  size_t h,
+  size_t w,
+  size_t c,
+  size_t cr,
+  size_t y_start,
+  size_t y_end,
+  size_t x_start,
+  size_t x_end,
+  const uint8_t* k,
+  const int32_t* b,
+  void* packed_w,
+  bool pack_b)
